package com.duoc.msgestion.service; import com.duoc.msgestion.model.Producto; import com.duoc.msgestion.repository.ProductoRepository; import org.springframework.beans.factory.annotation.Autowired; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import java.util.List; @Service public class ProductoService { @Autowired private ProductoRepository repository; @Transactional(readOnly = true) public List<Producto> listarTodosLosProductos() { return repository.findAll(); } @Transactional public Producto guardarProducto(Producto producto) { if(producto.getPrecio() < 0) { throw new IllegalArgumentException("El precio no puede ser negativo"); } return repository.save(producto); } }